const fs = require('fs');
const path = require('path');

function readLogFile(filename) {
    const allowedDirectory = '/allowed/logs/directory/'; // Replace with your allowed directory

    try {
        const resolvedPath = path.resolve(__dirname, filename);
        if (!resolvedPath.startsWith(allowedDirectory)) {
            throw new Error('File path is not allowed');
        }

        return fs.readFileSync(resolvedPath, 'utf8');
    } catch (error) {
        return `Error: ${error.message}`;
    }
}

module.exports = readLogFile;